  ('promotion-1aab856d-moex-00089', 'promotion-1aab856d', 'promotion-1aab856d-moex-110-3082b5f1', 'sub-promotion-1aab856d-02', NULL, 'single_choice', '內政部警政署委由縣警察局辦理外國人永久居留等事項。甲為美國籍外國人，向縣警察局申請永 久居留，經縣警察局審核後認甲不符法定申請資格，甲不服，欲提起訴願。下列何者正確？', '["內政部警政署與縣警察局為行政委託關係", "訴願管轄機關為內政部警政署", "訴願管轄機關為內政部", "訴願管轄機關為縣政府"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "130", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "移民行政"}'::jsonb, NULL),
  ('promotion-1aab856d-moex-00090', 'promotion-1aab856d', 'promotion-1aab856d-moex-110-3082b5f1', 'sub-promotion-1aab856d-02', NULL, 'single_choice', '下列何者屬於委託行使公權力行為？', '["機關辦公處所清潔勞務之委託", "機關委託民間業者實施汽車定期檢驗業務", "警察指揮民間拖吊業者實施交通違規車輛拖吊業務", "公營事業的經營活動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "130", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "移民行政"}'::jsonb, NULL),
  ('promotion-1aab856d-moex-00091', 'promotion-1aab856d', 'promotion-1aab856d-moex-110-3082b5f1', 'sub-promotion-1aab856d-02', NULL, 'single_choice', '甲所有的部分土地長期供公眾通行使用，鄉公所並鋪設柏油道路，設置路燈及負責道路修繕。經 過數十年鄰地的聯外道路系統已相當發達，已少有公眾使用該既成道路。甲希望能使用供公眾使 用既成道路的土地，擬向行政法院提起訴訟恢復既成道路上土地得自由使用收益狀態。甲應提起 下列何種行政訴訟？', '["撤銷之訴", "一般給付之訴", "所有權返還之訴", "確認公法法律關係存否之訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "130", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "移民行政"}'::jsonb, NULL),
  ('promotion-1aab856d-moex-00092', 'promotion-1aab856d', 'promotion-1aab856d-moex-110-3082b5f1', 'sub-promotion-1aab856d-02', NULL, 'single_choice', '甲市政府基於成本考量將該市所興建所有的焚化爐，委託乙公司運作經營。由於乙公司人員操作 焚化爐不當，釋放大量戴奧辛等有毒氣體致周邊居民吸入後產生健康的危害。請問受害居民應如 何求償，以下敘述何者正確？', '["甲市政府既已將焚化爐委託乙公司經營管理，受害居民僅能向乙公司行使民事侵權行為之損害 賠償，國家並無責任", "受害人民仍得以甲市政府為賠償義務機關提起國家賠償之訴，不論該焚化爐是否已經委託乙公 司經營管理", "受害人民對於其身體健康的損害，必須證明乙公司人員操作焚化爐有過失，始能請求國家賠償", "受害人民對於身體健康之損害，僅能擇一向乙公司提起民事損害賠償之訴，或以甲市政府為賠 償義務機關提起國家賠償之訴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "130", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "移民行政"}'::jsonb, NULL),
  ('promotion-1aab856d-moex-00093', 'promotion-1aab856d', 'promotion-1aab856d-moex-110-3082b5f1', 'sub-promotion-1aab856d-02', NULL, 'single_choice', '駕駛人於路邊停車格內停車，主管機關因該處地層下陷，緊急遂請拖吊業者將其車移至適當地點。 駕駛人事後發覺車輛因移置而受有損害。其可提出何種救濟？', '["向法院提起國家賠償", "向主管機關提起民事損害賠償", "向拖吊業者提起民事損害賠償", "向主管機關請求損失補償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:42+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "130", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "移民行政"}'::jsonb, NULL),
  ('promotion-29a002de-moex-00001', 'promotion-29a002de', 'promotion-29a002de-moex-114-8d1d3a67', 'sub-promotion-29a002de-01', NULL, 'essay', '甲遭乙檢舉利用手機販毒，警員丙進入手機通訊軟體，發現甲有「快樂
天堂」之代號，遂發問「我是乙介紹喔，品質如何？」，甲回以「好朋友，
品質保證、試過就知道」等，後約好地方交貨，甲一出現，即遭警員丙
逮捕，並在甲身上搜到毒品後扣押。試問，該扣案毒品可否做為法院認
定甲有罪之證據？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "06193b2227c9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "123", "s": "0510", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "司法行政"}'::jsonb, NULL),
  ('promotion-29a002de-moex-00002', 'promotion-29a002de', 'promotion-29a002de-moex-114-8d1d3a67', 'sub-promotion-29a002de-01', NULL, 'essay', '甲某日在某超商外等朋友，突然聽見超商內有人大喊「抓住那個穿紅色
背心的，他是搶匪」，隨即看到身穿紅色背心的乙衝出超商大門後急奔而
去。偵查終結後乙遭起訴，審判中，甲到庭作證，證稱「他當時不在超
商內，但確實有聽到當時超商內不知名的人大喊：『抓住那個穿紅色背心
的，他是搶匪』。」試問，甲的證詞是否有證據能力？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "06193b2227c9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "123", "s": "0510", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "司法行政"}'::jsonb, NULL),
  ('promotion-29a002de-moex-00003', 'promotion-29a002de', 'promotion-29a002de-moex-114-8d1d3a67', 'sub-promotion-29a002de-01', NULL, 'essay', '甲因涉及販賣毒品遭到偵查，檢察官傳喚乙出庭作證，乙詳述甲如何販
賣之經過。甲遭起訴後，聲請法院傳乙到庭接受詰問，惟乙因另案逃亡
遭通緝，無法順利到庭接受詰問。法院遂提示紀錄乙在偵查中所述之筆
錄，問甲有無辯解，甲稱乙之陳述均屬捏造，不足採信。後法院仍依據
此一筆錄及其他證據綜合判斷後，判甲有罪。試問，法院此一判決是否
合法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "06193b2227c9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "123", "s": "0510", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "司法行政"}'::jsonb, NULL)
